// OMNI EDGE V1
// -----------------------------------------------------------------------------
// Compositor multi-regime para BTC Up/Down 5 minutos.
// Pega o melhor de:
//   - Terminal Convexity V1    (regime tau ~ 8..15s)
//   - Stable Carry Compression (regime tau ~ 30..120s)
//   - Lead Inertia Mispricing  (regime tau ~ 120..290s)
//   - Gamma Ladder V1          (box arb + ladder direcional)
//   - Cofre Sete V1            (motor agressivo multi-perna)
//   - Impulse Elasticity V1    (shock + book lag, qualquer tau)
//   - Edge Sniper V1           (direcional defensivo)
//   - Volatility Compression L. (lock barato, mid event)
//
// Diferenciais sobre Fusion Five V1:
//   1. Alocacao bayesiana adaptativa por modulo:
//        - prior Beta(alpha0, beta0) sobre P(win) do modulo
//        - apos cada trade fechado, atualiza posterior
//        - usa Wilson lower bound (LB) para gating; modulo so "vale" se LB>0.5
//        - tamanho efetivo do trade escala pelo Kelly fracionario
//          aproximado f = max(0, 2*pHat - 1) * kellyMultiplier, clamp [0, 2]
//   2. Pausa automatica por streak:
//        - se rolling N trades de um modulo somar < -lossStreakBudget,
//          o modulo entra em "cooldown" por cooldownSec antes de re-entrar
//   3. Cap cross-modular de exposicao por evento:
//        - soma de custo de todos os modulos comprando no mesmo evento
//          eh limitada por maxEventStackCost
//   4. Gate de regime por volatilidade do BTC:
//        - calcula realized vol global (1h) e bloqueia modulos direcionais
//          quando vol > volPanicThreshold (vol extrema). Edge Sniper, Impulse
//          e box do Gamma continuam liberados.
//   5. Halt global de drawdown:
//        - se PnL cumulativo cair globalHaltDrawdown abaixo do pico, suspende
//          novas entradas de TODOS os modulos ate o pico ser recuperado.
//   6. Cross-stack pruning:
//        - quando varios modulos disparam no mesmo evento e mesmo lado, prefere
//          o trade com maior cost-eficacia (edge/spread) e ignora os redundantes
//          do mesmo lado.
//
// O service mantem o shape padrao dos backtests promovidos:
//   - createOmniEdgeBacktestRunner(rawParams)
//   - runOmniEdgeBacktest(rawParams, ticks)
//   - runOmniEdgeBacktestInBatches(rawParams, tickBatches)










const MODULES = [
  { key: 'terminal',    name: 'Terminal Convexity V1',        paramsKey: 'terminalParams',    directional: true,  priorityDefault: 5 },
  { key: 'lead',        name: 'Lead Inertia Mispricing V1',              paramsKey: 'leadParams',        directional: true,  priorityDefault: 1 },
  { key: 'stable',      name: 'Stable Carry Compression V1',   paramsKey: 'stableParams',      directional: true,  priorityDefault: 2 },
  { key: 'gamma',       name: 'Gamma Ladder V1',              paramsKey: 'gammaParams',       directional: false, priorityDefault: 3 },
  { key: 'cofre',       name: 'Cofre Sete V1',                paramsKey: 'cofreParams',       directional: true,  priorityDefault: 4 },
  { key: 'impulse',     name: 'Impulse Elasticity V1',        paramsKey: 'impulseParams',     directional: true,  priorityDefault: 6 },
  { key: 'edge',        name: 'Edge Sniper V1',               paramsKey: 'edgeParams',        directional: true,  priorityDefault: 7 },
  { key: 'vcl',         name: 'Volatility Compression Lock V1', paramsKey: 'vclParams',         directional: true,  priorityDefault: 8 },
];

const DEFAULT_INCLUDED = ['lead', 'stable', 'gamma', 'terminal', 'cofre', 'impulse', 'edge'];

const DEFAULT_PARAMS = {
  walletSize: 100,
  includeModules: DEFAULT_INCLUDED,
  // Alocador Bayesiano
  bayes: {
    priorAlpha: 8,
    priorBeta: 8,
    wilsonZ: 1.0,        // z para 84% LB (defensivo mas nao paralisante)
    minWilsonLb: 0.50,   // LB de winrate exigido para liberar o modulo
    warmupTrades: 5,     // antes de N trades, libera por default
    kellyMultiplier: 0.5,
    minSizeFactor: 0.20,
    maxSizeFactor: 1.50,
  },
  // Pausa por streak
  streak: {
    rollingWindow: 12,
    lossBudgetPctWallet: 0.20,
    cooldownSec: 12 * 3600,
  },
  // Cap cross-modular por evento
  maxEventStackCost: 60,
  maxModulesPerEvent: 3,
  // Halt global
  globalHaltDrawdown: 200,
  // Gate de regime
  regimeGate: {
    enabled: true,
    volWindowSec: 3600,
    volPanicThreshold: 6.0,  // USD/s — calibrado para o periodo recente
    spareNonDirectional: true,
  },
  // Cross-stack dedup
  dedupSameSidePreferEdge: true,
};

function toFiniteNumber(value, fallback = null) {
  if (value == null || value === '') return fallback;
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function toBool(value, fallback = false) {
  if (value == null) return fallback;
  return value === true || value === 'true' || value === 1 || value === '1';
}

function normalizeStringList(value, fallback) {
  if (Array.isArray(value)) {
    const clean = value.map((item) => String(item).trim()).filter(Boolean);
    return clean.length ? clean : fallback;
  }
  if (typeof value === 'string') {
    const clean = value.split(',').map((item) => item.trim()).filter(Boolean);
    return clean.length ? clean : fallback;
  }
  return fallback;
}

function normalizeObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function clamp(value, min, max) {
  return Math.min(max, Math.max(min, value));
}

function mergeOmniEdgeParams(raw = {}) {
  const params = {
    ...DEFAULT_PARAMS,
    bayes: { ...DEFAULT_PARAMS.bayes, ...normalizeObject(raw.bayes) },
    streak: { ...DEFAULT_PARAMS.streak, ...normalizeObject(raw.streak) },
    regimeGate: { ...DEFAULT_PARAMS.regimeGate, ...normalizeObject(raw.regimeGate) },
  };

  for (const module of MODULES) {
    params[module.paramsKey] = normalizeObject(raw[module.paramsKey] ?? raw[module.key] ?? {});
  }

  const walletSize = toFiniteNumber(raw.walletSize);
  if (walletSize != null) params.walletSize = Math.max(1, walletSize);

  for (const module of MODULES) {
    if (params[module.paramsKey].walletSize == null) {
      params[module.paramsKey] = { ...params[module.paramsKey], walletSize: params.walletSize };
    }
  }

  params.includeModules = normalizeStringList(raw.includeModules, DEFAULT_INCLUDED)
    .filter((key) => MODULES.some((module) => module.key === key));
  if (!params.includeModules.length) params.includeModules = [...DEFAULT_INCLUDED];

  if (raw.maxEventStackCost != null) {
    const v = toFiniteNumber(raw.maxEventStackCost);
    if (v != null) params.maxEventStackCost = Math.max(0.01, v);
  }
  if (raw.maxModulesPerEvent != null) {
    const v = toFiniteNumber(raw.maxModulesPerEvent);
    if (v != null) params.maxModulesPerEvent = Math.max(1, Math.floor(v));
  }
  if (raw.globalHaltDrawdown != null) {
    const v = toFiniteNumber(raw.globalHaltDrawdown);
    if (v != null) params.globalHaltDrawdown = Math.max(0.01, v);
  }
  if (raw.dedupSameSidePreferEdge != null) {
    params.dedupSameSidePreferEdge = toBool(raw.dedupSameSidePreferEdge, params.dedupSameSidePreferEdge);
  }

  params.bayes.priorAlpha = clamp(toFiniteNumber(params.bayes.priorAlpha, DEFAULT_PARAMS.bayes.priorAlpha), 0.1, 1000);
  params.bayes.priorBeta = clamp(toFiniteNumber(params.bayes.priorBeta, DEFAULT_PARAMS.bayes.priorBeta), 0.1, 1000);
  params.bayes.wilsonZ = clamp(toFiniteNumber(params.bayes.wilsonZ, DEFAULT_PARAMS.bayes.wilsonZ), 0, 5);
  params.bayes.minWilsonLb = clamp(toFiniteNumber(params.bayes.minWilsonLb, DEFAULT_PARAMS.bayes.minWilsonLb), 0, 1);
  params.bayes.warmupTrades = Math.max(0, Math.floor(toFiniteNumber(params.bayes.warmupTrades, DEFAULT_PARAMS.bayes.warmupTrades)));
  params.bayes.kellyMultiplier = clamp(toFiniteNumber(params.bayes.kellyMultiplier, DEFAULT_PARAMS.bayes.kellyMultiplier), 0, 5);
  params.bayes.minSizeFactor = clamp(toFiniteNumber(params.bayes.minSizeFactor, DEFAULT_PARAMS.bayes.minSizeFactor), 0, 5);
  params.bayes.maxSizeFactor = clamp(toFiniteNumber(params.bayes.maxSizeFactor, DEFAULT_PARAMS.bayes.maxSizeFactor), 0.01, 10);

  params.streak.rollingWindow = Math.max(1, Math.floor(toFiniteNumber(params.streak.rollingWindow, DEFAULT_PARAMS.streak.rollingWindow)));
  params.streak.lossBudgetPctWallet = clamp(toFiniteNumber(params.streak.lossBudgetPctWallet, DEFAULT_PARAMS.streak.lossBudgetPctWallet), 0, 10);
  params.streak.cooldownSec = Math.max(0, toFiniteNumber(params.streak.cooldownSec, DEFAULT_PARAMS.streak.cooldownSec));

  params.regimeGate.enabled = toBool(params.regimeGate.enabled, DEFAULT_PARAMS.regimeGate.enabled);
  params.regimeGate.volWindowSec = clamp(toFiniteNumber(params.regimeGate.volWindowSec, DEFAULT_PARAMS.regimeGate.volWindowSec), 30, 86400);
  params.regimeGate.volPanicThreshold = clamp(toFiniteNumber(params.regimeGate.volPanicThreshold, DEFAULT_PARAMS.regimeGate.volPanicThreshold), 0, 1000);
  params.regimeGate.spareNonDirectional = toBool(params.regimeGate.spareNonDirectional, DEFAULT_PARAMS.regimeGate.spareNonDirectional);

  return params;
}

// -----------------------------------------------------------------------------
// Bayesian helpers
// -----------------------------------------------------------------------------

function wilsonLower(wins, trials, z = 1.0) {
  if (trials <= 0) return 0;
  const p = wins / trials;
  const denom = 1 + (z * z) / trials;
  const center = p + (z * z) / (2 * trials);
  const margin = z * Math.sqrt((p * (1 - p) + (z * z) / (4 * trials)) / trials);
  return Math.max(0, (center - margin) / denom);
}

function rollingWindowPnl(history, windowSize) {
  if (!history.length) return 0;
  const slice = history.slice(-windowSize);
  return slice.reduce((sum, item) => sum + item.pnl, 0);
}

// -----------------------------------------------------------------------------
// Regime gate (realized vol of BTC across all ticks)
// -----------------------------------------------------------------------------

function buildRegimeIndex(allTicks, windowSec) {
  // Index: para cada minuto coberto pelos ticks, calcula realized vol em USD/s
  // baseada em uma janela movel de `windowSec` segundos.
  if (!allTicks.length || windowSec <= 0) return null;
  const sortedTs = allTicks.map((tick) => new Date(tick.ts).getTime());
  const prices = allTicks.map((tick) => toFiniteNumber(tick.btc_price));
  const buckets = new Map();
  const head = sortedTs[sortedTs.length - 1];
  const tail = sortedTs[0];
  if (!Number.isFinite(head) || !Number.isFinite(tail)) return null;
  let leftIdx = 0;
  for (let i = 1; i < sortedTs.length; i++) {
    const tNow = sortedTs[i];
    while (leftIdx < i && tNow - sortedTs[leftIdx] > windowSec * 1000) leftIdx++;
    if (i - leftIdx < 4) continue;
    let sumSq = 0;
    let n = 0;
    for (let j = leftIdx + 1; j <= i; j++) {
      const dt = (sortedTs[j] - sortedTs[j - 1]) / 1000;
      if (dt <= 0) continue;
      const dp = prices[j] - prices[j - 1];
      if (!Number.isFinite(dp)) continue;
      sumSq += (dp * dp) / dt;
      n += 1;
    }
    if (n < 4) continue;
    const realizedVol = Math.sqrt(sumSq / n); // USD / sqrt(s) ~ USD/s para passos curtos
    const bucketKey = Math.floor(tNow / 60000);
    const prev = buckets.get(bucketKey);
    if (prev == null || realizedVol > prev) buckets.set(bucketKey, realizedVol);
  }
  return buckets;
}

function lookupRegimeVol(buckets, ts) {
  if (!buckets) return null;
  const key = Math.floor(new Date(ts).getTime() / 60000);
  // tenta o bucket atual e os 2 anteriores
  for (let offset = 0; offset < 4; offset++) {
    const v = buckets.get(key - offset);
    if (v != null) return v;
  }
  return null;
}

// -----------------------------------------------------------------------------
// Event aggregation & decoration
// -----------------------------------------------------------------------------

function eventKey(event) {
  return `${event.eventStart}|${event.eventId}`;
}

function isActiveEvent(event) {
  return event && event.reason !== 'no_entry' && Number(event.cost || 0) > 0;
}

function decorate(module, event, extra = {}) {
  return {
    ...event,
    omniModule: module.key,
    omniModuleName: module.name,
    omniEventKey: eventKey(event),
    ...extra,
  };
}

function getEdgeScore(event) {
  const d = event.diagnostics || {};
  const edge = Number(d.modelEdge ?? d.edge ?? 0);
  const spread = Math.max(0.005, Number(d.spread ?? 0.02));
  return edge / spread;
}

function getSide(event) {
  return event.positionType || event.side || null;
}

function getEntryTs(event) {
  return event.entryTime || event.closedAt || event.eventEnd;
}

function rolloverPriority(params, moduleKey) {
  const ord = params.includeModules.indexOf(moduleKey);
  return ord === -1 ? 999 : ord;
}

// -----------------------------------------------------------------------------
// Selection algorithm
// -----------------------------------------------------------------------------

function selectOmniEvents(params, moduleResults, regimeBuckets) {
  // Constroi lista cronologica de TODOS os trades candidatos
  const candidates = [];
  for (const moduleResult of moduleResults) {
    if (!params.includeModules.includes(moduleResult.key)) continue;
    for (const event of moduleResult.result.events || []) {
      if (!isActiveEvent(event)) continue;
      candidates.push({
        module: moduleResult,
        event,
        ts: new Date(getEntryTs(event)).getTime(),
        endTs: new Date(event.closedAt || event.eventEnd).getTime(),
        priority: rolloverPriority(params, moduleResult.key),
        edgeScore: getEdgeScore(event),
        side: getSide(event),
        eventKey: eventKey(event),
      });
    }
  }
  candidates.sort((left, right) => {
    if (left.ts !== right.ts) return left.ts - right.ts;
    if (left.priority !== right.priority) return left.priority - right.priority;
    return right.edgeScore - left.edgeScore;
  });

  // Estado por modulo: posterior Beta(alpha, beta), history rolante e cooldown
  const moduleState = new Map();
  for (const moduleResult of moduleResults) {
    moduleState.set(moduleResult.key, {
      alpha: params.bayes.priorAlpha,
      beta: params.bayes.priorBeta,
      trades: 0,
      wins: 0,
      history: [], // [{ts, pnl}]
      cooldownUntilTs: 0,
    });
  }

  // Estado por evento: custo acumulado, modulos ja entrados, lados ja tomados
  const perEvent = new Map();

  // Estado global
  let globalPnl = 0;
  let globalPeak = 0;

  const selected = [];
  const rejected = []; // diagnostico

  const lossBudget = params.streak.lossBudgetPctWallet * params.walletSize;
  const haltDD = params.globalHaltDrawdown;

  for (const candidate of candidates) {
    const ms = moduleState.get(candidate.module.key);
    const mod = candidate.module;
    const event = candidate.event;
    const reasonsRejected = [];

    // Halt global
    const curDrawdown = globalPeak - globalPnl;
    if (haltDD > 0 && curDrawdown >= haltDD) {
      reasonsRejected.push('global_halt');
      rejected.push({ candidate, reasons: reasonsRejected });
      continue;
    }

    // Cooldown
    if (candidate.ts < ms.cooldownUntilTs) {
      reasonsRejected.push('cooldown');
      rejected.push({ candidate, reasons: reasonsRejected });
      continue;
    }

    // Bayes Wilson LB
    if (ms.trades >= params.bayes.warmupTrades) {
      const lb = wilsonLower(ms.wins, ms.trades, params.bayes.wilsonZ);
      if (lb < params.bayes.minWilsonLb) {
        reasonsRejected.push('wilson_lb');
        rejected.push({ candidate, reasons: reasonsRejected, wilsonLb: lb });
        continue;
      }
    }

    // Regime gate
    if (params.regimeGate.enabled) {
      const isDirectional = mod.definition.directional;
      const sparedByNonDir = params.regimeGate.spareNonDirectional && !isDirectional;
      if (isDirectional || !sparedByNonDir) {
        const vol = lookupRegimeVol(regimeBuckets, candidate.ts);
        if (vol != null && vol > params.regimeGate.volPanicThreshold && isDirectional) {
          reasonsRejected.push('regime_vol_panic');
          rejected.push({ candidate, reasons: reasonsRejected, vol });
          continue;
        }
      }
    }

    // Per-event caps
    const pe = perEvent.get(candidate.eventKey) || { cost: 0, modules: new Set(), sidesBySide: new Map() };
    const cost = Number(event.cost || 0);
    if (pe.modules.size >= params.maxModulesPerEvent && !pe.modules.has(mod.key)) {
      reasonsRejected.push('max_modules');
      rejected.push({ candidate, reasons: reasonsRejected });
      continue;
    }
    if (pe.cost + cost > params.maxEventStackCost) {
      reasonsRejected.push('event_stack_cap');
      rejected.push({ candidate, reasons: reasonsRejected });
      continue;
    }

    // Dedup mesmo lado (manter o de maior edge score)
    if (params.dedupSameSidePreferEdge && candidate.side) {
      const existing = pe.sidesBySide.get(candidate.side);
      if (existing && existing.edgeScore >= candidate.edgeScore) {
        reasonsRejected.push('dedup_same_side');
        rejected.push({ candidate, reasons: reasonsRejected });
        continue;
      }
    }

    // Aprovado: comita
    pe.cost += cost;
    pe.modules.add(mod.key);
    if (candidate.side) pe.sidesBySide.set(candidate.side, candidate);
    perEvent.set(candidate.eventKey, pe);

    const finalPnl = Number(event.finalPnl || 0);
    globalPnl += finalPnl;
    if (globalPnl > globalPeak) globalPeak = globalPnl;

    // Atualiza estado bayesiano do modulo
    ms.trades += 1;
    if (finalPnl > 0) {
      ms.wins += 1;
      ms.alpha += 1;
    } else if (finalPnl < 0) {
      ms.beta += 1;
    }
    ms.history.push({ ts: candidate.ts, pnl: finalPnl });
    if (ms.history.length > params.streak.rollingWindow * 2) {
      ms.history.splice(0, ms.history.length - params.streak.rollingWindow * 2);
    }

    // Streak halting
    const rollPnl = rollingWindowPnl(ms.history, params.streak.rollingWindow);
    if (rollPnl < -lossBudget) {
      ms.cooldownUntilTs = candidate.ts + params.streak.cooldownSec * 1000;
    }

    const wilsonLb = wilsonLower(ms.wins, ms.trades, params.bayes.wilsonZ);
    const pHat = ms.alpha / (ms.alpha + ms.beta);
    const kelly = Math.max(0, 2 * pHat - 1) * params.bayes.kellyMultiplier;
    const sizeFactor = clamp(kelly, params.bayes.minSizeFactor, params.bayes.maxSizeFactor);

    selected.push(decorate(mod, event, {
      omniWilsonLb: wilsonLb,
      omniPHat: pHat,
      omniKellyFactor: sizeFactor,
      omniGlobalPnl: globalPnl,
    }));
  }

  return { selected, rejected, moduleState };
}

// -----------------------------------------------------------------------------
// Display events + summary
// -----------------------------------------------------------------------------

function buildDisplayEvents(selectedEvents, moduleResults) {
  // Constroi "no_entry" para eventos do universo que nao foram aceitos
  const universe = new Map();
  for (const moduleResult of moduleResults) {
    for (const event of moduleResult.result.events || []) {
      const key = eventKey(event);
      if (!universe.has(key)) universe.set(key, event);
    }
  }
  const selectedKeys = new Set(selectedEvents.map((event) => event.omniEventKey));
  const list = [...selectedEvents];
  for (const [key, base] of universe.entries()) {
    if (selectedKeys.has(key)) continue;
    list.push({
      eventId: base.eventId,
      eventStart: base.eventStart,
      eventEnd: base.eventEnd,
      positionType: null,
      entryTime: null,
      entryDistanceToPtb: null,
      entryTimeRemaining: null,
      quantity: 0,
      cost: 0,
      avgEntryPrice: 0,
      fills: [],
      profitOrders: [],
      exits: [],
      expirationResult: null,
      winnerSide: base.winnerSide ?? null,
      expiryPnl: 0,
      finalPnl: 0,
      reason: 'no_entry',
      closedAt: base.closedAt || base.eventEnd,
      diagnostics: null,
      omniModule: null,
      omniModuleName: null,
      omniEventKey: key,
    });
  }
  return list.sort((left, right) => new Date(left.closedAt || left.eventEnd) - new Date(right.closedAt || right.eventEnd));
}

function std(values) {
  if (values.length < 2) return 0;
  const avg = values.reduce((sum, v) => sum + v, 0) / values.length;
  return Math.sqrt(values.reduce((sum, v) => sum + (v - avg) ** 2, 0) / values.length);
}

function buildSummary(allEvents, selectedEvents, params, moduleResults) {
  const pnls = selectedEvents.map((event) => Number(event.finalPnl || 0));
  const wins = pnls.filter((v) => v > 0);
  const losses = pnls.filter((v) => v < 0);
  const totalPnl = pnls.reduce((sum, v) => sum + v, 0);
  const grossProfit = wins.reduce((sum, v) => sum + v, 0);
  const grossLoss = losses.reduce((sum, v) => sum + Math.abs(v), 0);
  const totalEntries = selectedEvents.length;
  const totalWins = wins.length;
  const totalLosses = losses.length;
  const avgPnl = totalEntries > 0 ? totalPnl / totalEntries : 0;
  const avgWin = wins.length ? grossProfit / wins.length : 0;
  const avgLoss = losses.length ? grossLoss / losses.length : 0;
  const pnlStd = std(pnls);
  const downsideStd = std(losses);
  const uniqueMarket = new Set(allEvents.map((event) => event.omniEventKey)).size;
  const activeMarket = new Set(selectedEvents.map((event) => event.omniEventKey)).size;

  let cumulative = 0;
  let peak = 0;
  let maxDrawdown = 0;
  const equity = [];
  for (const event of allEvents) {
    cumulative += Number(event.finalPnl || 0);
    if (cumulative > peak) peak = cumulative;
    if (peak - cumulative > maxDrawdown) maxDrawdown = peak - cumulative;
    equity.push({ ts: event.closedAt || event.eventEnd, pnl: cumulative });
  }

  const byModule = {};
  for (const event of selectedEvents) {
    const key = event.omniModule;
    if (!byModule[key]) byModule[key] = { module: key, entries: 0, pnl: 0, wins: 0, losses: 0 };
    byModule[key].entries += 1;
    byModule[key].pnl += Number(event.finalPnl || 0);
    if (Number(event.finalPnl) > 0) byModule[key].wins += 1;
    else if (Number(event.finalPnl) < 0) byModule[key].losses += 1;
  }

  return {
    totalEvents: uniqueMarket,
    totalEntries,
    activeEvents: activeMarket,
    stackedEntries: Math.max(0, totalEntries - activeMarket),
    totalNoEntry: Math.max(0, uniqueMarket - activeMarket),
    totalWins,
    totalLosses,
    winRate: totalEntries > 0 ? parseFloat(((totalWins / totalEntries) * 100).toFixed(1)) : 0,
    totalPnl,
    avgPnl,
    maxWin: pnls.length ? Math.max(...pnls) : 0,
    maxLoss: pnls.length ? Math.min(...pnls) : 0,
    maxDrawdown,
    finalWallet: params.walletSize + totalPnl,
    grossProfit,
    grossLoss,
    profitFactor: grossLoss > 0 ? grossProfit / grossLoss : (grossProfit > 0 ? Number.POSITIVE_INFINITY : 0),
    payoff: avgLoss > 0 ? avgWin / avgLoss : (avgWin > 0 ? Number.POSITIVE_INFINITY : 0),
    expectancy: avgPnl,
    sharpe: pnlStd > 0 ? avgPnl / pnlStd : 0,
    sortino: downsideStd > 0 ? avgPnl / downsideStd : 0,
    modules: Object.values(byModule),
    baselines: moduleResults.map((item) => ({
      key: item.key,
      name: item.name,
      pnl: item.result.summary?.totalPnl ?? 0,
      entries: item.result.summary?.totalEntries ?? 0,
      winRate: item.result.summary?.winRate ?? 0,
      profitFactor: item.result.summary?.profitFactor ?? 0,
      maxDrawdown: item.result.summary?.maxDrawdown ?? 0,
    })),
  };
}

// -----------------------------------------------------------------------------
// Public runner
// -----------------------------------------------------------------------------

function createBacktestRunner(rawParams = {}, loadChildRunner) {
  const params = mergeOmniEdgeParams(rawParams);

  const activeModules = MODULES.filter((mod) => params.includeModules.includes(mod.key));
  const __MODULE_SLUGS__ = {
  "terminal": "terminal-convexity-runner",
  "lead": "lead-inertia-runner",
  "stable": "stable-carry-compression-runner",
  "gamma": "gamma-ladder-runner",
  "cofre": "cofre-sete-runner",
  "impulse": "impulse-elasticity-runner",
  "edge": "edge-sniper-runner",
  "vcl": "volatility-compression-lock-runner"
};
  const runners = activeModules.map((definition) => ({
    key: definition.key,
    name: definition.name,
    definition,
    runner: loadChildRunner(__MODULE_SLUGS__[definition.key], 1, params[definition.paramsKey] || {}),
  }));

  // Para o regime gate, precisamos manter as series de BTC ao longo do tempo.
  // Mantemos amostragem leve (1 sample por 250ms) para conter memoria.
  const regimeSamples = [];
  let lastRegimeSampleMs = 0;

  const processTick = (tick) => {
    for (const r of runners) r.runner.processTick(tick);
    const tms = new Date(tick.ts).getTime();
    const btcPrice = toFiniteNumber(tick.btc_price);
    if (Number.isFinite(tms) && btcPrice != null) {
      if (tms - lastRegimeSampleMs >= 250) {
        regimeSamples.push({ ts: tick.ts, btc_price: btcPrice });
        lastRegimeSampleMs = tms;
      }
    }
  };

  const finish = () => {
    const moduleResults = runners.map((r) => ({
      key: r.key,
      name: r.name,
      definition: r.definition,
      result: r.runner.finish(),
    }));

    const regimeBuckets = params.regimeGate.enabled
      ? buildRegimeIndex(regimeSamples, params.regimeGate.volWindowSec)
      : null;

    const { selected, rejected, moduleState } = selectOmniEvents(params, moduleResults, regimeBuckets);
    const display = buildDisplayEvents(selected, moduleResults);
    const summary = buildSummary(display, selected, params, moduleResults);

    let cumulative = 0;
    const equity = [];
    for (const event of display) {
      cumulative += Number(event.finalPnl || 0);
      equity.push({ ts: event.closedAt || event.eventEnd, pnl: cumulative });
    }

    const moduleHealth = [];
    for (const [key, state] of moduleState.entries()) {
      moduleHealth.push({
        module: key,
        trades: state.trades,
        wins: state.wins,
        wilsonLb: wilsonLower(state.wins, state.trades, params.bayes.wilsonZ),
        posteriorMean: state.alpha / (state.alpha + state.beta),
        cooldownUntilTs: state.cooldownUntilTs || null,
      });
    }

    return {
      params,
      strategy: 'OMNI_EDGE_V1',
      summary,
      equity,
      events: display,
      moduleResults: moduleResults.map((item) => ({
        key: item.key,
        name: item.name,
        summary: item.result.summary,
        strategy: item.result.strategy,
      })),
      moduleHealth,
      rejected: rejected.slice(0, 500).map((r) => ({
        module: r.candidate.module.key,
        eventKey: r.candidate.eventKey,
        ts: r.candidate.event.closedAt,
        reasons: r.reasons,
      })),
      log: [],
      ticksProcessed: moduleResults.reduce((max, item) => Math.max(max, item.result.ticksProcessed || 0), 0),
      periodStart: moduleResults.find((item) => item.result.periodStart)?.result.periodStart || null,
      periodEnd: [...moduleResults].reverse().find((item) => item.result.periodEnd)?.result.periodEnd || null,
    };
  };

  return { processTick, finish };
}

function runOmniEdgeBacktest(rawParams, ticks) {
  const runner = createOmniEdgeBacktestRunner(rawParams);
  for (const tick of ticks) runner.processTick(tick);
  return runner.finish();
}

async function runOmniEdgeBacktestInBatches(rawParams, tickBatches) {
  const runner = createOmniEdgeBacktestRunner(rawParams);
  for await (const batch of tickBatches) {
    for (const tick of batch) runner.processTick(tick);
  }
  return runner.finish();
}
